package src.org.apache.nutch.fetcher;

public class QueueFeeder extends Thread { private static final Logger LOG = LoggerFactory . getLogger ( MethodHandles . lookup ( ) . lookupClass ( ) ) ; private FetcherRun . Context context ; private FetchItemQueues queues ; private int size ; private long timelimit = - 1 ; public QueueFeeder ( FetcherRun . Context context , FetchItemQueues queues , int size ) { this . context = context ; this . queues = queues ; this . size = size ; this . setDaemon ( true ) ; this . setName ( "QueueFeeder" ) ; } public void setTimeLimit ( long tl ) { timelimit = tl ; } public void run ( ) { boolean hasMore = true ; int cnt = 0 ; int timelimitcount = 0 ; while ( hasMore ) { if ( System . currentTimeMillis ( ) >= timelimit && timelimit != - 1 ) { try { hasMore = context . nextKeyValue ( ) ; timelimitcount ++ ; } catch ( IOException e ) { LOG . error ( "QueueFeeder error reading input, record " + cnt , e ) ; return ; } catch ( InterruptedException e ) { LOG . info ( "QueueFeeder interrupted, exception:" , e ) ; return ; } continue ; } int feed = size - queues . getTotalSize ( ) ; if ( feed <= 0 ) { try { Thread . sleep ( 1000 ) ; } catch ( Exception e ) { } ; continue ; } else { LOG . debug ( "-feeding {} input urls ..." , feed ) ; while ( feed > 0 && hasMore ) { try { hasMore = context . nextKeyValue ( ) ; if ( hasMore ) { Text url = new Text ( ( Text ) context . getCurrentKey ( ) ) ; CrawlDatum datum = new CrawlDatum ( ) ; datum . set ( ( CrawlDatum ) context . getCurrentValue ( ) ) ; queues . addFetchItem ( url , datum ) ; cnt ++ ; feed -- ; } } catch ( IOException e ) { LOG . error ( "QueueFeeder error reading input, record " + cnt , e ) ; return ; } catch ( InterruptedException e ) { LOG . info ( "QueueFeeder interrupted, exception:" , e ) ; } } } } LOG . info ( "QueueFeeder finished: total {} records hit by time limit : {}" , cnt , timelimitcount ) ; } }